  1→// pa24r — P-Code Assembler for COR24
  2→
  3→pub mod lexer;
  4→
  5→// .p24 header constants
  6→pub const P24_MAGIC: [u8; 4] = [0x50, 0x32, 0x34, 0x00]; // "P24\0"
  7→pub const P24_VERSION: u8 = 1;
  8→pub const P24_HEADER_SIZE: usize = 18;
  9→
 10→/// Encoding format for p-code instructions.
 11→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 12→pub enum Encoding {
 13→    /// 1 byte: [op]
 14→    None,
 15→    /// 2 bytes: [op, imm8]
 16→    Imm8,
 17→    /// 4 bytes: [op, lo, mid, hi]
 18→    Imm24,
 19→    /// 5 bytes: [op, d8, lo, mid, hi]
 20→    D8A24,
 21→    /// 3 bytes: [op, d8, o8]
 22→    D8O8,
 23→}
 24→
 25→impl Encoding {
 26→    /// Total instruction size in bytes (including opcode byte).
 27→    pub const fn size(self) -> usize {
 28→        match self {
 29→            Encoding::None => 1,
 30→            Encoding::Imm8 => 2,
 31→            Encoding::Imm24 => 4,
 32→            Encoding::D8A24 => 5,
 33→            Encoding::D8O8 => 3,
 34→        }
 35→    }
 36→}
 37→
 38→/// All 36 p-code opcodes. Values match pvm.s ground truth.
 39→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 40→#[repr(u8)]
 41→pub enum Opcode {
 42→    // Stack operations
 43→    Halt = 0x00,
 44→    Push = 0x01,
 45→    PushS = 0x02,
 46→    Dup = 0x03,
 47→    Drop = 0x04,
 48→    Swap = 0x05,
 49→    Over = 0x06,
 50→
 51→    // Arithmetic
 52→    Add = 0x10,
 53→    Sub = 0x11,
 54→    Mul = 0x12,
 55→    Div = 0x13,
 56→    Mod = 0x14,
 57→    Neg = 0x15,
 58→
 59→    // Comparison
 60→    Eq = 0x20,
 61→    Ne = 0x21,
 62→    Lt = 0x22,
 63→    Le = 0x23,
 64→    Gt = 0x24,
 65→    Ge = 0x25,
 66→
 67→    // Logic
 68→    And = 0x26,
 69→    Or = 0x27,
 70→    Not = 0x28,
 71→
 72→    // Control flow
 73→    Jmp = 0x30,
 74→    Jz = 0x31,
 75→    Jnz = 0x32,
 76→    Call = 0x33,
 77→    Ret = 0x34,
 78→    RetV = 0x35,
 79→    Trap = 0x36,
 80→
 81→    // Frame management
 82→    Enter = 0x40,
 83→    Leave = 0x41,
 84→    Loadl = 0x42,
 85→    Storel = 0x43,
 86→    Loada = 0x44,
 87→    Storea = 0x45,
 88→
 89→    // Memory (global + indirect)
 90→    Load = 0x50,
 91→    Store = 0x51,
 92→    Loadb = 0x52,
 93→    Storeb = 0x53,
 94→    Loadg = 0x54,
 95→    Storeg = 0x55,
 96→    Addrg = 0x56,
 97→    Addrl = 0x57,
 98→
 99→    // Nonlocal access
100→    Loadn = 0x58,
101→    Storen = 0x59,
102→    Calln = 0x5A,
103→
104→    // System calls
105→    Sys = 0x60,
106→}
107→
108→impl Opcode {
109→    /// Return the encoding format for this opcode.
110→    pub const fn encoding(self) -> Encoding {
111→        match self {
112→            // NONE encoding (1 byte)
113→            Opcode::Halt
114→            | Opcode::Dup
115→            | Opcode::Drop
116→            | Opcode::Swap
117→            | Opcode::Over
118→            | Opcode::Add
119→            | Opcode::Sub
120→            | Opcode::Mul
121→            | Opcode::Div
122→            | Opcode::Mod
123→            | Opcode::Neg
124→            | Opcode::Eq
125→            | Opcode::Ne
126→            | Opcode::Lt
127→            | Opcode::Le
128→            | Opcode::Gt
129→            | Opcode::Ge
130→            | Opcode::And
131→            | Opcode::Or
132→            | Opcode::Not
133→            | Opcode::Leave
134→            | Opcode::Load
135→            | Opcode::Store
136→            | Opcode::Loadb
137→            | Opcode::Storeb => Encoding::None,
138→
139→            // IMM8 encoding (2 bytes)
140→            Opcode::PushS
141→            | Opcode::Ret
142→            | Opcode::RetV
143→            | Opcode::Trap
144→            | Opcode::Enter
145→            | Opcode::Loadl
146→            | Opcode::Storel
147→            | Opcode::Loada
148→            | Opcode::Storea
149→            | Opcode::Addrl
150→            | Opcode::Sys => Encoding::Imm8,
151→
152→            // IMM24 encoding (4 bytes)
153→            Opcode::Push
154→            | Opcode::Jmp
155→            | Opcode::Jz
156→            | Opcode::Jnz
157→            | Opcode::Call
158→            | Opcode::Loadg
159→            | Opcode::Storeg
160→            | Opcode::Addrg => Encoding::Imm24,
161→
162→            // D8_A24 encoding (5 bytes)
163→            Opcode::Calln => Encoding::D8A24,
164→
165→            // D8_O8 encoding (3 bytes)
166→            Opcode::Loadn | Opcode::Storen => Encoding::D8O8,
167→        }
168→    }
169→
170→    /// Instruction size in bytes.
171→    pub const fn size(self) -> usize {
172→        self.encoding().size()
173→    }
174→
175→    /// Look up an opcode by its mnemonic string.
176→    pub fn from_mnemonic(name: &str) -> Option<Opcode> {
177→        match name {
178→            "halt" => Some(Opcode::Halt),
179→            "push" => Some(Opcode::Push),
180→            "push_s" => Some(Opcode::PushS),
181→            "dup" => Some(Opcode::Dup),
182→            "drop" => Some(Opcode::Drop),
183→            "swap" => Some(Opcode::Swap),
184→            "over" => Some(Opcode::Over),
185→            "add" => Some(Opcode::Add),
186→            "sub" => Some(Opcode::Sub),
187→            "mul" => Some(Opcode::Mul),
188→            "div" => Some(Opcode::Div),
189→            "mod" => Some(Opcode::Mod),
190→            "neg" => Some(Opcode::Neg),
191→            "eq" => Some(Opcode::Eq),
192→            "ne" => Some(Opcode::Ne),
193→            "lt" => Some(Opcode::Lt),
194→            "le" => Some(Opcode::Le),
195→            "gt" => Some(Opcode::Gt),
196→            "ge" => Some(Opcode::Ge),
197→            "and" => Some(Opcode::And),
198→            "or" => Some(Opcode::Or),
199→            "not" => Some(Opcode::Not),
200→            "jmp" => Some(Opcode::Jmp),
201→            "jz" => Some(Opcode::Jz),
202→            "jnz" => Some(Opcode::Jnz),
203→            "call" => Some(Opcode::Call),
204→            "ret" => Some(Opcode::Ret),
205→            "ret_v" => Some(Opcode::RetV),
206→            "trap" => Some(Opcode::Trap),
207→            "enter" => Some(Opcode::Enter),
208→            "leave" => Some(Opcode::Leave),
209→            "loadl" => Some(Opcode::Loadl),
210→            "storel" => Some(Opcode::Storel),
211→            "loada" => Some(Opcode::Loada),
212→            "storea" => Some(Opcode::Storea),
213→            "load" => Some(Opcode::Load),
214→            "store" => Some(Opcode::Store),
215→            "loadb" => Some(Opcode::Loadb),
216→            "storeb" => Some(Opcode::Storeb),
217→            "loadg" => Some(Opcode::Loadg),
218→            "storeg" => Some(Opcode::Storeg),
219→            "addrg" => Some(Opcode::Addrg),
220→            "addrl" => Some(Opcode::Addrl),
221→            "loadn" => Some(Opcode::Loadn),
222→            "storen" => Some(Opcode::Storen),
223→            "calln" => Some(Opcode::Calln),
224→            "sys" => Some(Opcode::Sys),
225→            _ => None,
226→        }
227→    }
228→}
