230→/// Result of assembling .spc source.
231→pub struct AssemblyResult {
232→    pub code: Vec<u8>,
233→    pub data: Vec<u8>,
234→    pub entry_point: u32,
235→    pub global_count: u32,
236→    pub errors: Vec<AssemblyError>,
237→}
