239→/// An error encountered during assembly.
240→#[derive(Debug)]
241→pub struct AssemblyError {
242→    pub line: usize,
243→    pub message: String,
244→}
245→
246→impl std::fmt::Display for AssemblyError {
247→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
248→        write!(f, "line {}: {}", self.line, self.message)
249→    }
250→}
