252→/// A loaded .p24 binary image.
253→pub struct LoadedImage {
254→    pub entry_point: u32,
255→    pub code: Vec<u8>,
256→    pub data: Vec<u8>,
257→    pub global_count: u32,
258→}
259→
260→/// Error loading a .p24 binary.
261→#[derive(Debug)]
262→pub enum LoadError {
263→    TooShort,
264→    BadMagic,
265→    BadVersion(u8),
266→    Truncated,
267→}
268→
269→impl std::fmt::Display for LoadError {
270→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
271→        match self {
272→            LoadError::TooShort => write!(f, "file too short for .p24 header"),
273→            LoadError::BadMagic => write!(f, "invalid .p24 magic bytes"),
274→            LoadError::BadVersion(v) => write!(f, "unsupported .p24 version: {v}"),
275→            LoadError::Truncated => write!(f, "file truncated: body shorter than header declares"),
276→        }
277→    }
278→}
