280→use std::collections::HashMap;
281→
282→use lexer::{Token, tokenize};
283→
284→/// Metadata directives from pl24r that we silently skip.
285→const METADATA_DIRECTIVES: &[&str] = &[".module", ".export", ".extern", ".endmodule"];
286→
287→/// Symbol type for tracking what kind of entity a name refers to.
288→#[derive(Debug, Clone, Copy)]
289→enum SymType {
290→    Code,
291→    Data,
292→    Global,
293→    Const,
294→}
295→
296→/// A symbol table entry.
297→#[derive(Debug, Clone)]
298→struct Symbol {
299→    value: u32,
300→    sym_type: SymType,
301→    line: usize,
302→}
303→
304→/// Assemble .spc source into separate code and data segments.
305→pub fn assemble(source: &str) -> AssemblyResult {
306→    let tokens = tokenize(source);
307→    let mut symbols: HashMap<String, Symbol> = HashMap::new();
308→    let mut errors: Vec<AssemblyError> = Vec::new();
309→    let mut data_bytes: Vec<u8> = Vec::new();
310→    let mut code_offset: u32 = 0;
311→    let mut data_offset: u32 = 0;
312→    let mut global_offset: u32 = 0;
313→    let mut entry_point: Option<u32> = None;
314→
315→    // ── Pass 1: Symbol Collection ──
316→
317→    let mut i = 0;
318→    while i < tokens.len() {
319→        let tok = &tokens[i];
320→        match &tok.token {
321→            Token::Newline => {
322→                i += 1;
323→            }
324→
325→            Token::Label(name) => {
326→                if let Err(e) =
327→                    insert_symbol(&mut symbols, name, code_offset, SymType::Code, tok.line)
328→                {
329→                    errors.push(e);
330→                }
331→                i += 1;
332→            }
333→
334→            Token::Directive(dir) => {
335→                let line = tok.line;
336→                i += 1;
337→                match dir.as_str() {
338→                    ".proc" => {
339→                        // .proc <name> <nargs>
340→                        let name = expect_identifier(&tokens, &mut i);
341→                        if let Some(name) = name {
342→                            if name == "main" {
343→                                entry_point = Some(code_offset);
344→                            }
345→                            if let Err(e) =
346→                                insert_symbol(&mut symbols, &name, code_offset, SymType::Code, line)
347→                            {
348→                                errors.push(e);
349→                            }
350→                        } else {
351→                            errors.push(AssemblyError {
352→                                line,
353→                                message: ".proc missing name".into(),
354→                            });
355→                        }
356→                        // Skip nargs (and any other trailing tokens on this line)
357→                        skip_to_newline(&tokens, &mut i);
358→                    }
359→                    ".end" => {
360→                        skip_to_newline(&tokens, &mut i);
361→                    }
362→                    ".data" => {
363→                        // .data <name> <byte>, <byte>, ...
364→                        let name = expect_identifier(&tokens, &mut i);
365→                        if let Some(name) = name {
366→                            if let Err(e) =
367→                                insert_symbol(&mut symbols, &name, data_offset, SymType::Data, line)
368→                            {
369→                                errors.push(e);
370→                            }
371→                        } else {
372→                            errors.push(AssemblyError {
373→                                line,
374→                                message: ".data missing name".into(),
375→                            });
376→                        }
377→                        // Collect bytes
378→                        while i < tokens.len() && tokens[i].token != Token::Newline {
379→                            match &tokens[i].token {
380→                                Token::Number(n) => {
381→                                    data_bytes.push(*n as u8);
382→                                    data_offset += 1;
383→                                    i += 1;
384→                                }
385→                                Token::Comma => {
386→                                    i += 1;
387→                                }
388→                                _ => {
389→                                    i += 1;
390→                                }
391→                            }
392→                        }
393→                    }
394→                    ".global" => {
395→                        // .global <name> <count>
396→                        let name = expect_identifier(&tokens, &mut i);
397→                        let count = expect_number(&tokens, &mut i).unwrap_or(1);
398→                        if let Some(name) = name {
399→                            if let Err(e) = insert_symbol(
400→                                &mut symbols,
401→                                &name,
402→                                global_offset,
403→                                SymType::Global,
404→                                line,
405→                            ) {
406→                                errors.push(e);
407→                            }
408→                        } else {
409→                            errors.push(AssemblyError {
410→                                line,
411→                                message: ".global missing name".into(),
412→                            });
413→                        }
414→                        global_offset += count as u32 * 3;
415→                        skip_to_newline(&tokens, &mut i);
416→                    }
417→                    ".const" => {
418→                        // .const <name> <value>
419→                        let name = expect_identifier(&tokens, &mut i);
420→                        let value = expect_number(&tokens, &mut i).unwrap_or(0);
421→                        if let Some(name) = name {
422→                            if let Err(e) = insert_symbol(
423→                                &mut symbols,
424→                                &name,
425→                                value as u32,
426→                                SymType::Const,
427→                                line,
428→                            ) {
429→                                errors.push(e);
430→                            }
431→                        } else {
432→                            errors.push(AssemblyError {
433→                                line,
434→                                message: ".const missing name".into(),
435→                            });
436→                        }
437→                        skip_to_newline(&tokens, &mut i);
438→                    }
439→                    d if METADATA_DIRECTIVES.contains(&d) => {
440→                        skip_to_newline(&tokens, &mut i);
441→                    }
442→                    _ => {
443→                        // Unknown directive — skip silently (may be from pl24r)
444→                        skip_to_newline(&tokens, &mut i);
445→                    }
446→                }
447→            }
448→
449→            Token::Identifier(name) => {
450→                // Instruction mnemonic
451→                let line = tok.line;
452→                if let Some(op) = Opcode::from_mnemonic(name) {
453→                    code_offset += op.size() as u32;
454→                    i += 1;
455→                    // Skip any operand tokens on this line
456→                    skip_to_newline(&tokens, &mut i);
457→                } else {
458→                    errors.push(AssemblyError {
459→                        line,
460→                        message: format!("unknown mnemonic: {name}"),
461→                    });
462→                    i += 1;
463→                    skip_to_newline(&tokens, &mut i);
464→                }
465→            }
466→
467→            _ => {
468→                i += 1;
469→            }
470→        }
471→    }
472→
473→    let code_size = code_offset;
474→    let data_size = data_offset;
475→    let global_count = global_offset / 3;
476→
477→    // Patch data symbols: add code_size
478→    // Patch global symbols: add code_size + data_size
479→    for sym in symbols.values_mut() {
480→        match sym.sym_type {
481→            SymType::Data => sym.value += code_size,
482→            SymType::Global => sym.value += code_size + data_size,
483→            SymType::Code | SymType::Const => {}
484→        }
485→    }
486→
487→    if entry_point.is_none() {
488→        errors.push(AssemblyError {
489→            line: 0,
490→            message: "missing .proc main".into(),
491→        });
492→    }
493→
494→    // ── Pass 2: Code Emission ──
495→
496→    let mut code: Vec<u8> = Vec::with_capacity(code_size as usize);
497→    i = 0;
498→    while i < tokens.len() {
499→        let tok = &tokens[i];
500→        match &tok.token {
501→            Token::Newline | Token::Label(_) | Token::Comma => {
502→                i += 1;
503→            }
504→
505→            Token::Directive(_) => {
506→                i += 1;
507→                skip_to_newline(&tokens, &mut i);
508→            }
509→
510→            Token::Identifier(name) => {
511→                let line = tok.line;
512→                if let Some(op) = Opcode::from_mnemonic(name) {
513→                    code.push(op as u8);
514→                    i += 1;
515→
516→                    match op.encoding() {
517→                        Encoding::None => {
518→                            // Ignore trailing operand (e.g. `ret 1`)
519→                            skip_to_newline(&tokens, &mut i);
520→                        }
521→                        Encoding::Imm8 => {
522→                            let val = resolve_operand(&tokens, &mut i, &symbols, line, &mut errors);
523→                            code.push(val as u8);
524→                            skip_to_newline(&tokens, &mut i);
525→                        }
526→                        Encoding::Imm24 => {
527→                            let val = resolve_operand(&tokens, &mut i, &symbols, line, &mut errors);
528→                            emit_le24(&mut code, val);
529→                            skip_to_newline(&tokens, &mut i);
530→                        }
531→                        Encoding::D8A24 => {
532→                            // d8, a24 — two operands (depth, address)
533→                            let d = resolve_operand(&tokens, &mut i, &symbols, line, &mut errors);
534→                            // skip comma if present
535→                            if i < tokens.len() && tokens[i].token == Token::Comma {
536→                                i += 1;
537→                            }
538→                            let a = resolve_operand(&tokens, &mut i, &symbols, line, &mut errors);
539→                            code.push(d as u8);
540→                            emit_le24(&mut code, a);
541→                            skip_to_newline(&tokens, &mut i);
542→                        }
543→                        Encoding::D8O8 => {
544→                            // d8, o8 — two operands
545→                            let d = resolve_operand(&tokens, &mut i, &symbols, line, &mut errors);
546→                            if i < tokens.len() && tokens[i].token == Token::Comma {
547→                                i += 1;
548→                            }
549→                            let o = resolve_operand(&tokens, &mut i, &symbols, line, &mut errors);
550→                            code.push(d as u8);
551→                            code.push(o as u8);
552→                            skip_to_newline(&tokens, &mut i);
553→                        }
554→                    }
555→                } else {
556→                    // Unknown mnemonic — already reported in pass 1
557→                    i += 1;
558→                    skip_to_newline(&tokens, &mut i);
559→                }
560→            }
561→
562→            _ => {
563→                i += 1;
564→            }
565→        }
566→    }
567→
568→    AssemblyResult {
569→        code,
570→        data: data_bytes,
571→        entry_point: entry_point.unwrap_or(0),
572→        global_count,
573→        errors,
574→    }
575→}
576→
577→/// Assemble .spc source and produce a complete .p24 binary.
578→pub fn assemble_to_p24(source: &str) -> Result<Vec<u8>, Vec<AssemblyError>> {
579→    let result = assemble(source);
580→    if !result.errors.is_empty() {
581→        return Err(result.errors);
582→    }
583→
584→    let mut binary = Vec::with_capacity(P24_HEADER_SIZE + result.code.len() + result.data.len());
585→
586→    // Header
587→    binary.extend_from_slice(&P24_MAGIC);
588→    binary.push(P24_VERSION);
589→    emit_le24(&mut binary, result.entry_point);
590→    emit_le24(&mut binary, result.code.len() as u32);
591→    emit_le24(&mut binary, result.data.len() as u32);
592→    emit_le24(&mut binary, result.global_count);
593→    binary.push(0x00); // flags
594→
595→    // Body
596→    binary.extend_from_slice(&result.code);
597→    binary.extend_from_slice(&result.data);
598→
599→    Ok(binary)
600→}
601→
602→/// Load a .p24 binary into a LoadedImage.
603→pub fn load_p24(binary: &[u8]) -> Result<LoadedImage, LoadError> {
604→    if binary.len() < P24_HEADER_SIZE {
605→        return Err(LoadError::TooShort);
606→    }
607→    if binary[0..4] != P24_MAGIC {
608→        return Err(LoadError::BadMagic);
609→    }
610→    let version = binary[4];
611→    if version != P24_VERSION {
612→        return Err(LoadError::BadVersion(version));
613→    }
614→
615→    let entry_point = read_le24(&binary[5..8]);
616→    let code_size = read_le24(&binary[8..11]) as usize;
617→    let data_size = read_le24(&binary[11..14]) as usize;
618→    let global_count = read_le24(&binary[14..17]);
619→
620→    let body = &binary[P24_HEADER_SIZE..];
621→    if body.len() < code_size + data_size {
622→        return Err(LoadError::Truncated);
623→    }
624→
625→    Ok(LoadedImage {
626→        entry_point,
627→        code: body[..code_size].to_vec(),
628→        data: body[code_size..code_size + data_size].to_vec(),
629→        global_count,
630→    })
631→}
632→
633→// ── Helper functions ──
634→
635→fn insert_symbol(
636→    symbols: &mut HashMap<String, Symbol>,
637→    name: &str,
638→    value: u32,
639→    sym_type: SymType,
640→    line: usize,
641→) -> Result<(), AssemblyError> {
642→    if let Some(existing) = symbols.get(name) {
643→        return Err(AssemblyError {
644→            line,
645→            message: format!(
646→                "duplicate symbol '{name}' (first defined at line {})",
647→                existing.line
648→            ),
649→        });
650→    }
651→    symbols.insert(
652→        name.to_string(),
653→        Symbol {
654→            value,
655→            sym_type,
656→            line,
657→        },
658→    );
659→    Ok(())
660→}
661→
662→fn expect_identifier(tokens: &[lexer::Located], i: &mut usize) -> Option<String> {
663→    if *i < tokens.len()
664→        && let Token::Identifier(name) = &tokens[*i].token
665→    {
666→        let name = name.clone();
667→        *i += 1;
668→        return Some(name);
669→    }
670→    None
671→}
672→
673→fn expect_number(tokens: &[lexer::Located], i: &mut usize) -> Option<i32> {
674→    if *i < tokens.len()
675→        && let Token::Number(n) = &tokens[*i].token
676→    {
677→        let n = *n;
678→        *i += 1;
679→        return Some(n);
680→    }
681→    None
682→}
683→
684→fn skip_to_newline(tokens: &[lexer::Located], i: &mut usize) {
685→    while *i < tokens.len() && tokens[*i].token != Token::Newline {
686→        *i += 1;
687→    }
688→}
689→
690→fn resolve_operand(
691→    tokens: &[lexer::Located],
692→    i: &mut usize,
693→    symbols: &HashMap<String, Symbol>,
694→    line: usize,
695→    errors: &mut Vec<AssemblyError>,
696→) -> u32 {
697→    if *i >= tokens.len() || tokens[*i].token == Token::Newline {
698→        errors.push(AssemblyError {
699→            line,
700→            message: "missing operand".into(),
701→        });
702→        return 0;
703→    }
704→    match &tokens[*i].token {
705→        Token::Number(n) => {
706→            let val = *n;
707→            *i += 1;
708→            val as u32
709→        }
710→        Token::Identifier(name) => {
711→            *i += 1;
712→            if let Some(sym) = symbols.get(name.as_str()) {
713→                sym.value
714→            } else {
715→                errors.push(AssemblyError {
716→                    line,
717→                    message: format!("unresolved symbol: {name}"),
718→                });
719→                0
720→            }
721→        }
722→        _ => {
723→            errors.push(AssemblyError {
724→                line,
725→                message: format!("unexpected token as operand: {:?}", tokens[*i].token),
726→            });
727→            *i += 1;
728→            0
729→        }
730→    }
731→}
732→
733→fn emit_le24(out: &mut Vec<u8>, val: u32) {
734→    out.push(val as u8);
735→    out.push((val >> 8) as u8);
736→    out.push((val >> 16) as u8);
737→}
738→
739→fn read_le24(bytes: &[u8]) -> u32 {
740→    u32::from(bytes[0]) | (u32::from(bytes[1]) << 8) | (u32::from(bytes[2]) << 16)
741→}
